def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        factor = 1.0
        complex_penalty = 0.0
        dynamic_adjustment = 1.0
        exponential_factor = 1.0
        for a in range(1, 15):
            if a % 4 == 0:
                factor *= 1.02 + 0.015 * a
            elif a % 6 == 0:
                factor *= 0.97 - 0.007 * a
            if ratio < 0.07 * a:
                base_score += ((a ** 3) / (2 + np.exp(ratio * a))) * factor
            else:
                base_score += (np.log1p(a*a*a) + ratio**4) * factor / (a + 3)
            if (cap * a + a*a) % 9 == 0:
                base_score *= 1.05
            elif (cap + a*a*a) % 11 == 0:
                base_score *= 0.93
            if a == 8:
                for b in range(1, 8):
                    diff = cap - item * (b**3)
                    if diff > 0:
                        if diff % (b+3) == 0:
                            complex_penalty += np.cbrt(diff) / (b + 4)
                        else:
                            complex_penalty -= np.log1p(abs(diff)) / (b + 3)
                    else:
                        complex_penalty -= abs(diff) ** 1.5 / (b + 7)
            if ratio > 0.8 and a % 3 == 0:
                dynamic_adjustment *= 1.12 + 0.025 * a
            elif ratio < 0.15 and a % 5 == 0:
                dynamic_adjustment *= 0.88 - 0.015 * a
            if a % 5 == 2 and cap % (a+2) == 0:
                complex_penalty += np.cos(a * ratio) * 0.6
            if a % 7 == 4 and cap % (a+4) == 0:
                dynamic_adjustment *= 1.03
            if a % 2 == 1:
                exponential_factor *= np.exp(-0.03 * a * ratio)
            else:
                exponential_factor *= np.exp(0.02 * a * ratio)
        base_score += complex_penalty * 0.85
        base_score *= dynamic_adjustment
        base_score *= exponential_factor
        if base_score <= 0:
            priorities[i] = -base_score * (np.log1p(cap + item) + np.sqrt(cap) + np.cbrt(item + 1))
        else:
            if cap > item * 5:
                priorities[i] = -base_score / (np.sqrt(cap) + 1.5) * (1 + ratio * 1.1)
            else:
                priorities[i] = -base_score / (cap + 4) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[i] *= 1.18
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        else:
            priorities[i] *= 1.01
        if cap % 4 == 0 and ratio < 0.5:
            priorities[i] *= 0.95
        elif cap % 4 == 1 and ratio > 0.7:
            priorities[i] *= 1.07
    return priorities
